sql:
SELECT track_id, title, duration
FROM tracks
WHERE duration > (SELECT AVG(duration) FROM tracks);

SELECT DISTINCT u.username
FROM users u
INNER JOIN lyric_reports lr ON u.user_id = lr.user_id;

SELECT DISTINCT u.username, u.email 
FROM users u 
INNER JOIN lyric_reports lr ON u.user_id = lr.user_id;

SELECT COUNT(*) 
FROM track_genres 
WHERE genre_id = 0;

SELECT title, duration / 60 AS duration_minutes
FROM tracks
WHERE duration > (
  SELECT AVG(duration) FROM tracks
)
ORDER BY duration DESC;

